// LESSON: Reference Page 1 - Metoder och parametrar.
// You will learn: Pass values, mutate referenced objects, and use varargs deliberately.
class Prog2Reference424 {
  // EXEMPEL 1: En metod kan ta parametrar och returnera ett varde.
  static int max(int a, int b) {
    return a >= b ? a : b;
  }
  // EXEMPEL 2: En referensparameter kan anvandas for att andra samma objekt.
  static void addName(java.util.List<String> names, String name) {
    if (name != null && !name.trim().isEmpty()) { names.add(name.trim()); }
  }
  // EXEMPEL 3: Varargs later anroparen skicka valfritt antal argument.
  static int sum(int... values) {
    int total = 0;
    for (int value : values) { total += value; }
    return total;
  }
}
